import { useEffect, useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { useHaptics } from '../hooks/useHaptics';

export const BreathingCircle = ({ onComplete }) => {
    const { breatheIn, breatheOut } = useHaptics();
    const [phase, setPhase] = useState('inhale'); // 'inhale', 'hold', 'exhale'
    const [timeLeft, setTimeLeft] = useState(60);

    useEffect(() => {
        if (timeLeft <= 0) {
            onComplete();
            return;
        }
        const timer = setInterval(() => setTimeLeft(prev => prev - 1), 1000);
        return () => clearInterval(timer);
    }, [timeLeft, onComplete]);

    useEffect(() => {
        let timeout;
        if (phase === 'inhale') {
            breatheIn();
            timeout = setTimeout(() => setPhase('hold'), 4000);
        } else if (phase === 'hold') {
            timeout = setTimeout(() => setPhase('exhale'), 2000);
        } else if (phase === 'exhale') {
            breatheOut();
            timeout = setTimeout(() => setPhase('inhale'), 6000);
        }
        return () => clearTimeout(timeout);
    }, [phase, breatheIn, breatheOut]);

    const getCircleScale = () => {
        if (phase === 'inhale') return 1.5;
        if (phase === 'hold') return 1.5;
        return 1;
    };

    const getPhaseText = () => {
        if (phase === 'inhale') return 'Breathe In...';
        if (phase === 'hold') return 'Hold...';
        return 'Breathe Out...';
    };

    return (
        <div className="flex flex-col items-center justify-center flex-1 w-full space-y-16">
            <div className="text-xl text-cyan-200 opacity-80 number-font">{timeLeft}s remaining</div>

            <div className="relative flex items-center justify-center w-64 h-64">
                <motion.div
                    animate={{ scale: getCircleScale() }}
                    transition={{ duration: phase === 'inhale' ? 4 : phase === 'exhale' ? 6 : 2, ease: "easeInOut" }}
                    className="absolute inset-0 rounded-full glow-cyan bg-cyan-900/30"
                />
                {[1, 2, 3].map(i => (
                    <motion.div
                        key={`bc-ring-${i}`}
                        animate={{ scale: phase === 'inhale' ? 1 + (i * 0.2) : 1, opacity: phase === 'exhale' ? 0.8 : 0.3 }}
                        transition={{ duration: phase === 'inhale' ? 4 : phase === 'exhale' ? 6 : 2, delay: i * 0.15, ease: 'easeInOut' }}
                        className="absolute inset-0 rounded-full border border-cyan-500/30 pointer-events-none"
                    />
                ))}
                <AnimatePresence mode="wait">
                    <motion.h2
                        key={phase}
                        initial={{ opacity: 0, y: 10 }}
                        animate={{ opacity: 1, y: 0 }}
                        exit={{ opacity: 0, y: -10 }}
                        className="z-10 text-2xl font-light tracking-widest text-white drop-shadow-lg"
                    >
                        {getPhaseText()}
                    </motion.h2>
                </AnimatePresence>
            </div>
        </div>
    );
};

import { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';

const MAPPING = [
    { count: 5, sense: "SEE 👁", color: "from-cyan-900/40 to-blue-900/40" },
    { count: 4, sense: "FEEL ✋", color: "from-violet-900/40 to-fuchsia-900/40" },
    { count: 3, sense: "HEAR 👂", color: "from-amber-900/40 to-orange-900/40" },
    { count: 2, sense: "SMELL 👃", color: "from-emerald-900/40 to-teal-900/40" },
    { count: 1, sense: "TASTE 👅", color: "from-rose-900/40 to-pink-900/40" }
];

export const GroundingFlash = ({ onComplete }) => {
    const [step, setStep] = useState(0);

    const handleNext = () => {
        if (step < MAPPING.length - 1) {
            setStep(prev => prev + 1);
        } else {
            onComplete();
        }
    };

    const current = MAPPING[step];

    return (
        <div
            onClick={handleNext}
            className={`absolute inset-0 flex flex-col items-center justify-center cursor-pointer select-none bg-gradient-to-br ${current.color} transition-colors duration-1000 z-50`}
        >
            <AnimatePresence mode="wait">
                <motion.div
                    key={step}
                    initial={{ opacity: 0, scale: 0.9, filter: "blur(10px)" }}
                    animate={{ opacity: 1, scale: 1, filter: "blur(0px)" }}
                    exit={{ opacity: 0, scale: 1.1, filter: "blur(10px)" }}
                    transition={{ duration: 0.8 }}
                    className="flex flex-col items-center space-y-8"
                >
                    <div className="text-6xl font-bold number-font opacity-80">{current.count}</div>
                    <h2 className="text-3xl font-light tracking-wide text-center px-4">
                        things you can <span className="font-bold">{current.sense}</span>
                    </h2>
                    <div className="mt-12 text-sm uppercase tracking-widest opacity-50 animate-pulse">
                        Tap anywhere to continue
                    </div>
                </motion.div>
            </AnimatePresence>

            <div className="absolute bottom-12 flex space-x-4 z-50">
                {MAPPING.map((_, i) => (
                    <motion.div
                        key={`dot-${i}`}
                        animate={{
                            scale: i === step ? 1.5 : 1,
                            opacity: i === step ? 1 : 0.3,
                            backgroundColor: i === step ? "#00F5FF" : "#ffffff"
                        }}
                        className="w-2 h-2 rounded-full"
                    />
                ))}
            </div>
        </div>
    );
};

import { motion } from 'framer-motion';

export const StressOrb = ({ stressLevel }) => {
    const getOrbStyles = () => {
        switch (stressLevel) {
            case 'CRITICAL': return { color: 'glow-red', text: 'Let\'s Reset Now 🆘' };
            case 'HIGH': return { color: 'glow-orange', text: 'Stress Detected 🌩' };
            case 'MEDIUM': return { color: 'glow-amber', text: 'A Little Tense 🌤' };
            default: return { color: 'glow-cyan', text: 'You\'re Calm 🌊' };
        }
    };

    const { color, text } = getOrbStyles();

    return (
        <motion.div
            initial={{ opacity: 0, scale: 0.8 }}
            animate={{ opacity: 1, scale: 1 }}
            className="flex flex-col items-center justify-center space-y-6"
        >
            <motion.div
                animate={{ scale: [1, 1.05, 1] }}
                transition={{ repeat: Infinity, duration: 3, ease: "easeInOut" }}
                className={`w-48 h-48 rounded-full ${color} bg-black/20 flex items-center justify-center`}
            >
                <div className={`w-32 h-32 rounded-full ${color} opacity-70 blur-md`}></div>
            </motion.div>
            <h2 className="text-2xl font-bold tracking-wider">{text}</h2>
        </motion.div>
    );
};

import { useEffect, useState, useRef } from 'react';
import { motion } from 'framer-motion';
import { useTapRhythm } from '../hooks/useTapRhythm';
import { useAccelerometer } from '../hooks/useAccelerometer';
import { useLightSensor } from '../hooks/useLightSensor';

export const TapZone = ({ onAnalysisComplete }) => {
    const { tapSpeed, tapCount, isTracking, startTracking, stopTracking, handleTap } = useTapRhythm();
    const { rms } = useAccelerometer();
    const { lux } = useLightSensor();
    const [timeLeft, setTimeLeft] = useState(5);

    const latestData = useRef({ tapSpeed, onAnalysisComplete });

    useEffect(() => {
        latestData.current = { tapSpeed, onAnalysisComplete };
    }, [tapSpeed, onAnalysisComplete]);

    useEffect(() => {
        let timer;
        if (isTracking && timeLeft > 0) {
            timer = setInterval(() => setTimeLeft(prev => prev - 1), 1000);
        }
        return () => clearInterval(timer);
    }, [isTracking]);

    useEffect(() => {
        if (isTracking && timeLeft === 0) {
            stopTracking();
            latestData.current.onAnalysisComplete({ tapSpeed: latestData.current.tapSpeed });
        }
    }, [isTracking, timeLeft, stopTracking]);

    const getGlowColor = () => {
        if (tapSpeed > 4) return 'glow-red bg-red-900/40 text-red-500';
        if (tapSpeed > 2.5) return 'glow-amber bg-amber-900/40 text-amber-500';
        return 'glow-cyan bg-cyan-900/40 text-cyan-500';
    };

    return (
        <div className="relative flex flex-col items-center justify-center flex-1 w-full p-4 select-none">
            {/* Background Sensor Overlay */}
            <div className="absolute top-6 left-6 text-xs font-mono text-cyan-500/30 whitespace-nowrap z-0">
                <div className="animate-pulse">SYS.SENSORS_ACTIVE</div>
                <div>ACC_RMS: {rms ? rms.toFixed(2) : '0.00'} g</div>
                <div>AMB_LUM: {lux ? lux.toFixed(0) : '---'} lx</div>
            </div>

            <h2 className="z-10 text-xl mb-12 text-gray-300">
                {!isTracking ? "Tap gently to start" : `Analyzing: ${timeLeft}s`}
            </h2>

            <motion.div
                whileTap={{ scale: 0.95 }}
                onPointerDown={() => {
                    if (!isTracking && timeLeft === 5) startTracking();
                    handleTap();
                }}
                animate={{ scale: isTracking ? [1, 1.02, 1] : 1 }}
                transition={{ duration: 0.3 }}
                className={`z-10 w-64 h-64 rounded-full flex flex-col items-center justify-center cursor-pointer transition-colors duration-300 relative ${isTracking ? getGlowColor() : 'glow-violet bg-violet-900/30'}`}
            >
                {/* Secondary expanding rings */}
                {isTracking && [1, 2, 3].map(i => (
                    <motion.div
                        key={`ring-${i}`}
                        className="absolute inset-0 rounded-full border border-current opacity-20 pointer-events-none"
                        animate={{ scale: [1, 1 + (tapSpeed * 0.1 * i)], opacity: [0.5, 0] }}
                        transition={{ duration: 0.8, repeat: Infinity, delay: i * 0.2 }}
                    />
                ))}

                {isTracking ? (
                    <>
                        <span className="text-4xl font-bold number-font mb-2">{tapSpeed.toFixed(1)}</span>
                        <span className="text-sm opacity-70 tracking-widest">TAPS/SEC</span>
                    </>
                ) : (
                    <span className="text-center px-8 text-lg font-medium tracking-wide">Hold & tap to let us feel your stress</span>
                )}
            </motion.div>

            {isTracking && (
                <div className="z-10 mt-12 text-gray-400">
                    <span className="number-font">{tapCount}</span> total taps
                </div>
            )}
        </div>
    );
};

import React, { useState, useEffect } from 'react';
import { motion } from 'framer-motion';

export const BreathingGame = ({ onComplete }) => {
    const [timeLeft, setTimeLeft] = useState(60);
    const [phase, setPhase] = useState('inhale'); // inhale, exhale
    const [score, setScore] = useState(0);
    const [isHolding, setIsHolding] = useState(false);

    useEffect(() => {
        if (timeLeft <= 0) {
            onComplete({ gameScore: score });
            return;
        }
        const timer = setInterval(() => {
            setTimeLeft((prev) => prev - 1);
        }, 1000);
        return () => clearInterval(timer);
    }, [timeLeft, onComplete, score]);

    useEffect(() => {
        // Breathing cycle: 5s inhale, 5s exhale
        const cycle = setInterval(() => {
            setPhase((prev) => prev === 'inhale' ? 'exhale' : 'inhale');
        }, 5000);
        return () => clearInterval(cycle);
    }, []);

    useEffect(() => {
        let scoreTimer;
        if (isHolding) {
            scoreTimer = setInterval(() => {
                setScore((prev) => prev + 1);
            }, 100);
        }
        return () => clearInterval(scoreTimer);
    }, [isHolding]);

    const handlePointerDown = () => setIsHolding(true);
    const handlePointerUp = () => setIsHolding(false);

    return (
        <div className="flex flex-col items-center justify-center flex-1 w-full space-y-8 select-none"
            onPointerDown={handlePointerDown}
            onPointerUp={handlePointerUp}
            onPointerLeave={handlePointerUp}>
            <div className="text-cyan-400 text-4xl font-bold tracking-widest mb-4">
                0:{timeLeft.toString().padStart(2, '0')}
            </div>

            <motion.div
                animate={{
                    scale: phase === 'inhale' ? 1.5 : 0.8,
                    opacity: phase === 'inhale' ? 1 : 0.6
                }}
                transition={{ duration: 5, ease: "easeInOut" }}
                className="w-48 h-48 rounded-full bg-cyan-500/20 glow-cyan flex items-center justify-center border-2 border-cyan-400/50 relative"
            >
                <motion.div
                    animate={{ scale: isHolding ? 1.1 : 1 }}
                    className={`absolute w-full h-full rounded-full transition-colors duration-300 ${isHolding ? 'bg-cyan-400/30' : 'bg-transparent'}`}
                />
                <h2 className="text-2xl tracking-widest text-cyan-100 z-10 transition-transform font-bold">
                    {phase === 'inhale' ? 'INHALE' : 'EXHALE'}
                </h2>
            </motion.div>

            <div className="flex flex-col items-center space-y-2 pt-12">
                <p className="text-gray-400 tracking-wider text-sm transition-opacity duration-300" style={{ opacity: isHolding ? 0.5 : 1 }}>
                    PRESS AND HOLD TO SYNC
                </p>
                <p className="text-cyan-500 font-mono text-xl">Focus Score: {score}</p>
            </div>
        </div>
    );
};

